const required = ["contract_did", "contract_version", "correlation_id", "content_hash", "timestamp", "payload"];

for (const key of required) {
  if (msg.payload === undefined || msg.payload[key] === undefined) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: `Missing field: ${key}` };
    return msg;
  }
}

// Recompute the payload's content hash the same way the sender canonicalized
// it (JSON with keys sorted recursively, no extra whitespace) so a tampered
// or corrupted payload is rejected rather than blindly acknowledged.
function sortKeysDeep(value) {
  if (Array.isArray(value)) {
    return value.map(sortKeysDeep);
  }
  if (value && typeof value === "object") {
    return Object.keys(value).sort().reduce((acc, key) => {
      acc[key] = sortKeysDeep(value[key]);
      return acc;
    }, {});
  }
  return value;
}

const canonical = JSON.stringify(sortKeysDeep(msg.payload.payload));
const computedHash = "sha256:" + crypto.createHash("sha256").update(canonical).digest("hex");

if (computedHash !== msg.payload.content_hash) {
  msg.statusCode = 400;
  msg.headers = { "Content-Type": "application/json" };
  msg.payload = {
    error: "content_hash does not match the payload",
    expected: msg.payload.content_hash,
    computed: computedHash
  };
  return msg;
}

const activatedAt = new Date().toISOString();
const correlationId = msg.payload.correlation_id;

msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = {
  correlation_id: correlationId,
  payload_hash: computedHash,
  activated_at: activatedAt
};
return msg;
